svg.script:
const FACE_CENTER = { x: 12, y: 12 };

const svgEl = document.getElementById('cloudling');
const cloudGroup = document.getElementById('cloud-group');
const eyeGroup = document.getElementById('eye-group');
const eyeL = document.getElementById('eye-l');
const eyeR = document.getElementById('eye-r');
const eyeGrad = document.getElementById('eye-grad');

const EYE_BASE = {
  l: { x: 7.7, y: 9.5, h: 5, rx: 1.3 },
  r: { x: 13.7, y: 9.5, h: 5, rx: 1.3 }
};

const P = {
  /* V1 锁定数值 */
  SCALE_LOW: 0.96, BREATH_PERIOD: 5.0,
  MAX_ROT_DEG: 20, CLOUD_LAG: 0.20,
  EYE_MAX: 1.20, EYE_TRACK_TIME: 0.06, RECENTER_TIME: 0.45,
  FLOW_PERIOD: 5.5, FLOW_AMP: 4,
  BLINK_INTERVAL: 6.0, BLINK_DUR: 0.16,
  /* V2 新增 */
  DIST_NEAR: 6, DIST_FAR: 20, DIST_MAX_SCALE: 1.15, DIST_RECENTER: 0.5
};

let mouseInside = false;
let mouseVB = { x: 12, y: 12 };
let eyeOffset = { x: 0, y: 0 };
let cloudRotate = 0;
let curDistScale = 1.0;
let lastT = performance.now();

let nextBlinkT = 3 + Math.random() * 2;
let blinkActive = false;
let blinkStartT = 0;

svgEl.addEventListener('mousemove', e => {
  const r = svgEl.getBoundingClientRect();
  /* viewBox -12 -12 48 48 → 反算 mouseVB */
  mouseVB.x = (e.clientX - r.left) * (48 / r.width) - 12;
  mouseVB.y = (e.clientY - r.top) * (48 / r.height) - 12;
  mouseInside = true;
});
svgEl.addEventListener('mouseleave', () => mouseInside = false);
svgEl.addEventListener('mouseenter', () => mouseInside = true);

window.__cloudlingSetPointer = payload => {
  if (!payload || !Number.isFinite(payload.x) || !Number.isFinite(payload.y)) return;
  mouseVB.x = payload.x;
  mouseVB.y = payload.y;
  mouseInside = !!payload.inside;
};

function computeEyeTarget() {
  if (!mouseInside) return { x: 0, y: 0 };
  const dx = mouseVB.x - FACE_CENTER.x;
  const dy = mouseVB.y - FACE_CENTER.y;
  const dist = Math.hypot(dx, dy);
  if (dist < 0.01) return { x: 0, y: 0 };
  const sat = Math.tanh(dist / 6);
  return {
    x: (dx / dist) * sat * P.EYE_MAX,
    y: (dy / dist) * sat * P.EYE_MAX
  };
}

function getBlinkScale(t) {
  if (!blinkActive && t > nextBlinkT) {
    blinkActive = true;
    blinkStartT = t;
  }
  if (blinkActive) {
    const dt = t - blinkStartT;
    const half = P.BLINK_DUR / 2;
    if (dt < half) {
      return 1 - 0.94 * (dt / half);
    } else if (dt < P.BLINK_DUR) {
      return 0.06 + 0.94 * ((dt - half) / half);
    } else {
      blinkActive = false;
      nextBlinkT = t + P.BLINK_INTERVAL * (0.8 + Math.random() * 0.4);
    }
  }
  return 1;
}

function applyBlink(rect, base, scale) {
  const newH = Math.max(base.h * scale, 0.15);
  const newY = base.y + (base.h - newH) / 2;
  const newRx = Math.min(base.rx, newH / 2);
  rect.setAttribute('height', newH.toFixed(3));
  rect.setAttribute('y', newY.toFixed(3));
  rect.setAttribute('rx', newRx.toFixed(3));
  rect.setAttribute('ry', newRx.toFixed(3));
}

const startT = performance.now();
function loop(now) {
  const dt = (now - lastT) / 1000;
  lastT = now;
  const t = (now - startT) / 1000;

  /* 呼吸 scale */
  const phase = (Math.cos(2 * Math.PI * t / P.BREATH_PERIOD) + 1) / 2;
  const breathScale = P.SCALE_LOW + (1.0 - P.SCALE_LOW) * phase;

  /* 眼睛位置 */
  const target = computeEyeTarget();
  const eyeTime = mouseInside ? P.EYE_TRACK_TIME : P.RECENTER_TIME;
  const eyeRate = 1 - Math.exp(-dt / eyeTime);
  eyeOffset.x += (target.x - eyeOffset.x) * eyeRate;
  eyeOffset.y += (target.y - eyeOffset.y) * eyeRate;

  /* 云朵 rotate (eye.x 驱动 + lag) */
  const maxRot = P.MAX_ROT_DEG * Math.PI / 180;
  const targetRot = (eyeOffset.x / Math.max(P.EYE_MAX, 0.01)) * maxRot;
  cloudRotate += (targetRot - cloudRotate) * P.CLOUD_LAG;

  /* V2: 距离驱动 scale */
  let targetDistScale = 1.0;
  if (mouseInside) {
    const dx = mouseVB.x - FACE_CENTER.x;
    const dy = mouseVB.y - FACE_CENTER.y;
    const dist = Math.hypot(dx, dy);
    if (dist > P.DIST_NEAR) {
      const t01 = Math.min((dist - P.DIST_NEAR) / Math.max(P.DIST_FAR - P.DIST_NEAR, 0.01), 1);
      targetDistScale = 1.0 + (P.DIST_MAX_SCALE - 1.0) * t01;
    }
  }
  const distRate = 1 - Math.exp(-dt / P.DIST_RECENTER);
  curDistScale += (targetDistScale - curDistScale) * distRate;

  /* 应用 cloud transform — breath scale × distance scale 相乘 */
  const finalScale = breathScale * curDistScale;
  const angleDeg = cloudRotate * 180 / Math.PI;
  cloudGroup.setAttribute(
    'transform',
    `translate(12 12) rotate(${angleDeg.toFixed(3)}) scale(${finalScale.toFixed(4)}) translate(-12 -12)`
  );

  /* 眼睛 group transform */
  const eyeScale = curDistScale;
  eyeGroup.setAttribute(
    'transform',
    `translate(${eyeOffset.x.toFixed(3)} ${eyeOffset.y.toFixed(3)}) translate(12 12) scale(${eyeScale.toFixed(4)}) translate(-12 -12)`
  );

  /* 眨眼 */
  const blinkScale = getBlinkScale(t);
  applyBlink(eyeL, EYE_BASE.l, blinkScale);
  applyBlink(eyeR, EYE_BASE.r, blinkScale);

  /* 流动渐变 */
  const flowOffset = Math.sin(2 * Math.PI * t / P.FLOW_PERIOD) * P.FLOW_AMP;
  eyeGrad.setAttribute('y1', (3 + flowOffset).toFixed(2));
  eyeGrad.setAttribute('y2', (21 + flowOffset).toFixed(2));

  requestAnimationFrame(loop);
}

requestAnimationFrame(loop);
